/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * Formats the notification payload into a short text message and sends it
 * to the recipient's phone number. Implements a pluggable transport layer
 * (defaults to in-memory for testing).
 *
 * The adapter conforms to the NotificationAdapter interface and is registered
 * with NotificationService via registerAdapter().
 */

import type { NotificationPayload } from '../models/notification.js';
import type { NotificationAdapter, DeliveryResult } from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

/**
 * A formatted SMS message ready for transport.
 */
export interface SmsMessage {
  to: string;
  from: string;
  body: string;
}

/**
 * Transport function signature — abstracts the actual SMS sending mechanism.
 * Return a message ID on success, or throw on failure.
 */
export type SmsTransport = (message: SmsMessage) => Promise<string>;

/**
 * Configuration for the SMS adapter.
 */
export interface SmsAdapterConfig {
  /** Sender phone number or short code (e.g., "+15551234567"). */
  fromNumber: string;
  /** Optional: SMS provider API key. */
  apiKey?: string;
  /** Optional: custom transport function. If not provided, uses in-memory transport. */
  transport?: SmsTransport;
}

/**
 * Validate that a string looks like a phone number.
 * Accepts E.164 format (e.g., +15551234567) or digits-only (10+ digits).
 */
function isValidPhoneNumber(phone: string): boolean {
  return /^\+?[1-9]\d{6,14}$/.test(phone);
}

/**
 * Format a notification payload into a short SMS body.
 * SMS messages are limited, so we keep it concise: subject + truncated body.
 */
function formatSmsBody(payload: NotificationPayload): string {
  const maxLength = 160;
  const prefix = `${payload.subject}: `;
  const remaining = maxLength - prefix.length;

  if (remaining <= 0) {
    return payload.subject.slice(0, maxLength);
  }

  const body = payload.body.length > remaining
    ? payload.body.slice(0, remaining - 3) + '...'
    : payload.body;

  return prefix + body;
}

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private sentMessages: SmsMessage[] = [];
  private inMemoryTransport: SmsTransport;
  private transport: SmsTransport;

  constructor(private config: SmsAdapterConfig) {
    this.inMemoryTransport = async (message: SmsMessage) => {
      this.sentMessages.push(message);
      return `sms-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    };
    this.transport = config.transport ?? this.inMemoryTransport;
  }

  /**
   * Format a notification payload into an SMS message.
   */
  formatMessage(payload: NotificationPayload): SmsMessage {
    const to = payload.recipient.trim();
    return {
      to,
      from: this.config.fromNumber,
      body: formatSmsBody(payload),
    };
  }

  /**
   * Send an SMS notification.
   *
   * Steps: validate phone number → format message → send via transport.
   */
  async send(payload: NotificationPayload): Promise<DeliveryResult> {
    this.logger.info(`Preparing SMS to ${payload.recipient}: "${payload.subject}"`);

    const recipient = payload.recipient.trim();
    if (!recipient) {
      const error = 'Recipient phone number is empty';
      this.logger.error(error);
      return { success: false, error };
    }

    if (!isValidPhoneNumber(recipient)) {
      const error = `Invalid recipient phone number: ${recipient}`;
      this.logger.error(error);
      return { success: false, error };
    }

    const message = this.formatMessage(payload);

    try {
      const messageId = await this.transport(message);
      this.logger.info(`SMS delivered: ${messageId} to ${recipient}`);

      return {
        success: true,
        providerMetadata: {
          from: this.config.fromNumber,
          messageId,
        },
      };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Transport error';
      this.logger.error(`SMS delivery failed: ${errorMessage}`);
      return { success: false, error: errorMessage };
    }
  }

  /**
   * Get all messages sent through this adapter (for testing).
   */
  getSentMessages(): SmsMessage[] {
    return [...this.sentMessages];
  }

  /**
   * Clear sent message records (for testing).
   */
  clearSentMessages(): void {
    this.sentMessages = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import type { SmsTransport } from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    channel: 'sms',
    recipient: '+15551234567',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    priority: 'normal',
    metadata: { orderId: 'order-1', userId: 'user-1' },
    createdAt: new Date(),
    ...overrides,
  };
}

describe('SmsAdapter', () => {
  let adapter: SmsAdapter;

  beforeEach(() => {
    adapter = new SmsAdapter({ fromNumber: '+15559876543' });
  });

  describe('send', () => {
    it('should successfully send a valid SMS', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.providerMetadata?.from).toBe('+15559876543');
      expect(result.providerMetadata?.messageId).toBeDefined();
    });

    it('should record sent messages in-memory', async () => {
      await adapter.send(makePayload());

      const sent = adapter.getSentMessages();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('+15551234567');
      expect(sent[0]?.from).toBe('+15559876543');
      expect(sent[0]?.body).toContain('Order Confirmation');
    });

    it('should fail for empty recipient', async () => {
      const result = await adapter.send(makePayload({ recipient: '' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('empty');
    });

    it('should fail for invalid phone number', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-a-number' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid recipient phone number');
    });

    it('should fail for phone number that is too short', async () => {
      const result = await adapter.send(makePayload({ recipient: '+123' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid recipient phone number');
    });

    it('should handle transport errors gracefully', async () => {
      const failingTransport: SmsTransport = async () => {
        throw new Error('SMS gateway unreachable');
      };
      const failAdapter = new SmsAdapter({
        fromNumber: '+15559876543',
        transport: failingTransport,
      });

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMS gateway unreachable');
    });

    it('should use custom transport when provided', async () => {
      const transportedMessages: string[] = [];
      const customTransport: SmsTransport = async (message) => {
        transportedMessages.push(message.to);
        return 'custom-sms-id';
      };
      const customAdapter = new SmsAdapter({
        fromNumber: '+15559876543',
        transport: customTransport,
      });

      const result = await customAdapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.providerMetadata?.messageId).toBe('custom-sms-id');
      expect(transportedMessages).toEqual(['+15551234567']);
    });

    it('should trim whitespace from recipient', async () => {
      const result = await adapter.send(makePayload({ recipient: '  +15551234567  ' }));

      expect(result.success).toBe(true);
      const sent = adapter.getSentMessages();
      expect(sent[0]?.to).toBe('+15551234567');
    });
  });

  describe('formatMessage', () => {
    it('should format message with subject and body', () => {
      const message = adapter.formatMessage(makePayload());

      expect(message.to).toBe('+15551234567');
      expect(message.from).toBe('+15559876543');
      expect(message.body).toContain('Order Confirmation: order-1:');
      expect(message.body).toContain('Your order has been placed');
    });

    it('should truncate long messages to 160 characters', () => {
      const longBody = 'A'.repeat(300);
      const message = adapter.formatMessage(makePayload({ body: longBody }));

      expect(message.body.length).toBeLessThanOrEqual(160);
      expect(message.body).toContain('...');
    });
  });

  describe('clearSentMessages', () => {
    it('should clear all recorded messages', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentMessages()).toHaveLength(1);

      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toHaveLength(0);
    });
  });

  describe('channel property', () => {
    it('should report sms as its channel', () => {
      expect(adapter.channel).toBe('sms');
    });
  });
});

